mapper.select:
SELECT mm.*, u1.name as creator_name, u2.name as host_name, (SELECT COUNT(*) FROM minute_comments WHERE minute_id = mm.id) as comment_count, (SELECT COUNT(*) FROM minute_attachments WHERE minute_id = mm.id) as attachment_count FROM meeting_minutes mm LEFT JOIN users u1 ON mm.creator_id = u1.id LEFT JOIN users u2 ON mm.host_id = u2.id
AND (mm.title LIKE CONCAT('%', #{keyword}, '%') OR mm.summary LIKE CONCAT('%', #{keyword}, '%') OR mm.content LIKE CONCAT('%', #{keyword}, '%'))
AND mm.status = #{status}
AND mm.creator_id = #{creatorId}
AND mm.meeting_date >= #{startDate}
AND mm.meeting_date <= #{endDate}
ORDER BY mm.created_time DESC

mapper.update:
UPDATE meeting_minutes
title = #{title}, meeting_date = #{meetingDate}, meeting_time = #{meetingTime}, location = #{location}, host_id = #{hostId}, status = #{status}, current_version = #{currentVersion}, summary = #{summary}, content = #{content},
WHERE id = #{id}
